import React, { useState, useEffect, useCallback } from "react";
import { BrowserRouter as Router, Routes, Route, Navigate, Link } from "react-router-dom";
import { ToastContainer, toast } from "react-toastify";
import "react-toastify/dist/ReactToastify.css";

import Sidebar from "./components/Sidebar";
import Topbar from "./components/Topbar";
import AdminDashboard from "./pages/AdminDashboard";
import VolunteerDashboard from "./pages/VolunteerDashboard";
import LoginPage from "./pages/LoginPage";
import SignupPage from "./pages/SignupPage";
import NeedsPage from "./pages/NeedsPage";
import VolunteersPage from "./pages/VolunteersPage";
import MapPage from "./pages/MapPage";
import MatchingPage from "./pages/MatchingPage";
import SubmitNeed from "./pages/SubmitNeed";
import AddVolunteer from "./pages/AddVolunteer";
import LoadingSpinner from "./components/LoadingSpinner";

import { fetchPrioritizedNeeds, fetchVolunteers, fetchAssignments, seedDatabase } from "./utils/api";

const ProtectedRoute = ({ user, allowedRole, children }) => {
  if (!user) return <Navigate to="/login" replace />;
  if (allowedRole && user.role !== allowedRole) return <Navigate to={user.role === 'admin' ? '/admin-dashboard' : '/volunteer-dashboard'} replace />;
  return children;
};

export default function App() {
  const [user, setUser] = useState(() => JSON.parse(localStorage.getItem("user")));
  const [needs, setNeeds] = useState([]);
  const [volunteers, setVolunteers] = useState([]);
  const [assignments, setAssignments] = useState([]);
  const [loading, setLoading] = useState(true);
  const [seeding, setSeeding] = useState(false);

  const loadAll = useCallback(async () => {
    if (!user) {
      setLoading(false);
      return;
    }
    try {
      const [n, v, a] = await Promise.all([
        fetchPrioritizedNeeds(),
        fetchVolunteers(),
        fetchAssignments(),
      ]);
      setNeeds(n.data.data || []);
      setVolunteers(v.data.data || []);
      setAssignments(a.data.data || []);
    } catch (e) {
      console.error("Failed to load data", e);
      if (e.response?.status === 401) handleLogout();
    } finally {
      setLoading(false);
    }
  }, [user]);

  useEffect(() => { loadAll(); }, [loadAll]);

  const handleLogin = (userData) => {
    setUser(userData);
  };

  const handleLogout = () => {
    localStorage.removeItem("token");
    localStorage.removeItem("user");
    setUser(null);
    toast.info("Logged out successfully");
  };

  const handleSeed = async () => {
    if (!window.confirm("This will add sample needs and volunteers to Firestore. Continue?")) return;
    try {
      setSeeding(true);
      await seedDatabase();
      toast.success("Sample data seeded successfully!");
      await loadAll();
    } catch {
      toast.error("Seeding failed. Ensure backend is running and Firestore is configured.");
    } finally {
      setSeeding(false);
    }
  };

  const urgentCount = needs.filter((n) => n.urgency === "high" && n.status !== "completed").length;
  const availableCount = volunteers.filter((v) => v.availability).length;

  if (loading && user) return (
    <div style={{ display: "flex", justifyContent: "center", alignItems: "center", height: "100vh" }}>
      <LoadingSpinner message="Connecting to ReliefLink..." />
    </div>
  );

  return (
    <Router>
      <div className="app">
        <ToastContainer position="top-right" autoClose={3000} hideProgressBar={false} />

        <Routes>
          <Route path="/login" element={user ? <Navigate to={user.role === 'admin' ? '/admin-dashboard' : '/volunteer-dashboard'} replace /> : <LoginPage onLogin={handleLogin} />} />
          <Route path="/signup" element={<SignupPage />} />

          <Route path="/*" element={
            <div style={{ display: "flex", width: "100%", height: "100vh" }}>
              <Sidebar 
                user={user} 
                urgentCount={urgentCount} 
                availableCount={availableCount} 
              />
              <div className="main" style={{ flex: 1, display: "flex", flexDirection: "column" }}>
                <Topbar
                  user={user}
                  urgentCount={urgentCount}
                  availableCount={availableCount}
                  onSeed={handleSeed}
                  seeding={seeding}
                  onLogout={handleLogout}
                />
                <div className="content" style={{ flex: 1, overflowY: "auto", padding: 24 }}>
                  <Routes>
                    <Route path="/admin-dashboard" element={
                      <ProtectedRoute user={user} allowedRole="admin">
                        <AdminDashboard needs={needs} volunteers={volunteers} assignments={assignments} />
                      </ProtectedRoute>
                    } />

                    <Route path="/volunteer-dashboard" element={
                      <ProtectedRoute user={user} allowedRole="volunteer">
                        <VolunteerDashboard user={user} needs={needs} assignments={assignments} />
                      </ProtectedRoute>
                    } />

                    <Route path="/needs" element={
                      <ProtectedRoute user={user}>
                        <NeedsPage />
                      </ProtectedRoute>
                    } />

                    <Route path="/volunteers" element={
                      <ProtectedRoute user={user} allowedRole="admin">
                        <VolunteersPage assignments={assignments} />
                      </ProtectedRoute>
                    } />

                    <Route path="/map" element={
                      <ProtectedRoute user={user}>
                        <MapPage needs={needs} volunteers={volunteers} />
                      </ProtectedRoute>
                    } />

                    <Route path="/matching" element={
                      <ProtectedRoute user={user} allowedRole="admin">
                        <MatchingPage needs={needs} onAssign={loadAll} />
                      </ProtectedRoute>
                    } />

                    <Route path="/submit-need" element={
                      <ProtectedRoute user={user}>
                        <SubmitNeed />
                      </ProtectedRoute>
                    } />

                    <Route path="/add-volunteer" element={
                      <ProtectedRoute user={user}>
                        <AddVolunteer />
                      </ProtectedRoute>
                    } />

                    <Route path="/" element={<Navigate to={user?.role === 'admin' ? '/admin-dashboard' : '/volunteer-dashboard'} replace />} />
                  </Routes>
                </div>
              </div>
            </div>
          } />
        </Routes>
      </div>
    </Router>
  );
}
